.team-chip{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:10px;background:var(--bg-input);border:1px solid var(--border)}.team-chip .tav{width:36px;height:36px;border-radius:50%;background:var(--bg-card);display:flex;align-items:center;justify-content:center;font-weight:800;font-size:12px;color:var(--accent);flex-shrink:0;overflow:hidden}.team-chip .tav img{width:100%;height:100%;object-fit:cover}
.match-row{display:flex;align-items:center;gap:12px;padding:14px;border-radius:12px;background:var(--bg-input);border:1px solid var(--border);margin-bottom:8px;flex-wrap:wrap}.match-row .mt{flex:1;min-width:150px}.match-row .mn{font-weight:700;font-size:13px}.match-row .mv{font-size:11px;color:var(--text-dim)}.match-row .ma{display:flex;gap:6px;flex-shrink:0;flex-wrap:wrap}
.toast{position:fixed;top:20px;right:20px;z-index:200;padding:12px 20px;border-radius:12px;font-size:13px;font-weight:600;box-shadow:0 8px 24px rgba(0,0,0,0.30);animation:toastIn 0.3s ease-out forwards;display:flex;align-items:center;gap:8px;max-width:380px}.toast.ok{background:#166534;color:#bbf7d0}.toast.err{background:#7f1d1d;color:#fecaca}@keyframes toastIn{from{opacity:0;transform:translateX(40px)}to{opacity:1;transform:translateX(0)}}@keyframes toastOut{from{opacity:1;transform:translateX(0)}to{opacity:0;transform:translateX(40px)}}
.empty{text-align:center;color:var(--text-mute);padding:30px;font-size:13px}.note{font-size:10px;color:var(--text-mute);margin-top:8px}
.modal-overlay{display:none;position:fixed;inset:0;z-index:100;background:rgba(0,0,0,0.65);backdrop-filter:blur(6px);-webkit-backdrop-filter:blur(6px);align-items:center;justify-content:center;padding:16px}.modal-overlay.show{display:flex}.modal-overlay.show .modal-box{animation:modalPop 0.3s cubic-bezier(0.16,1,0.3,1) forwards}@keyframes modalPop{from{opacity:0;transform:scale(0.92) translateY(10px)}to{opacity:1;transform:scale(1) translateY(0)}}
.modal-box{background:var(--bg-card);border:1px solid var(--border);border-radius:18px;width:100%;max-width:460px;max-height:90vh;overflow:hidden;box-shadow:0 25px 60px rgba(0,0,0,0.50)}
.modal-header{background:linear-gradient(135deg,var(--accent),var(--accent2));padding:16px 20px;display:flex;align-items:center;justify-content:space-between;gap:10px}
.modal-header h3{font-size:14px;font-weight:700;color:#fff;margin:0;display:flex;align-items:center;gap:8px}.modal-header h3 .micon{font-size:18px}
.modal-close{background:rgba(255,255,255,0.15);border:none;color:#fff;width:28px;height:28px;border-radius:50%;cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center}.modal-close:hover{background:rgba(255,255,255,0.25)}
.modal-body{padding:20px;overflow-y:auto;max-height:calc(90vh - 60px)}.modal-body .form-group:last-child{margin-bottom:0}th.r,td.r{text-align:right}th.c,td.c{text-align:center}
