ottom:16px"><label style="display:block;font-size:10px;font-weight:600;color:var(--text-dim);margin-bottom:4px;text-transform:uppercase;letter-spacing:0.04em">New Password <span style="color:var(--text-mute);font-weight:400">(leave blank to keep)</span></label><input type="password" name="acc_new_pw" minlength="6" placeholder="Min 6 characters" style="width:100%;background:var(--bg-input);border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-size:13px;color:var(--text);font-family:inherit;outline:none"></div><div style="display:flex;gap:10px;justify-content:flex-end"><button type="button" onclick="this.closest(\'.dyn-modal\').remove()" class="btn btn-s">Cancel</button><button type="submit" class="btn btn-p">Save Changes</button></div></form></div>';d.style.cssText='position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,0.65);backdrop-filter:blur(6px);display:flex;align-items:center;justify-content:center;padding:16px';d.addEventListener('click',function(e){if(e.target===this)this.remove()});document.body.appendChild(d)}
function showLogoutModal(){var d=document.createElement('div');d.className='dyn-modal';d.innerHTML='<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:18px;width:100%;max-width:380px;text-align:center;overflow:hidden;box-shadow:0 25px 60px rgba(0,0,0,0.50)"><div style="padding:36px 28px 24px"><div style="width:64px;height:64px;border-radius:50%;background:rgba(239,68,68,0.10);display:flex;align-items:center;justify-content:center;margin:0 auto 16px;font-size:32px">&#128682;</div><h3 style="font-size:17px;font-weight:700;color:var(--text);margin-bottom:8px">Confirm Logout</h3><p style="font-size:13px;color:var(--text-dim);margin-bottom:24px;line-height:1.5">Are you sure you want to sign out of your account?</p><div style="display:flex;gap:10px;justify-content:center"><button type="button" onclick="this.closest(\'.dyn-modal\').remove()" class="btn btn-s">Cancel</button><a href="api.php?action=logout" class="btn btn-d" style="padding:9px 18px">&#128682; Logout</a></div></div></div>';d.style.cssText='position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,0.65);backdrop-filter:blur(6px);display:flex;align-items:center;justify-content:center;padding:16px';d.addEventListener('click',function(e){if(e.target===this)this.remove()});document.body.appendChild(d)}
function filterPlayers(){var s=document.getElementById('playerSearch'),t=document.getElementById('playerTeamFilter');if(!s||!t)return;s=s.value.toLowerCase();t=t.value;document.querySelectorAll('table tbody tr[data-name]').forEach(function(tr){tr.style.display=(!s||tr.getAttribute('data-name').includes(s))&&(!t||tr.getAttribute('data-team')===t)?'':'none';});}
</script>
